inline cx integrand_conv_8(const double* y, const double* params) {
    // Convergent sector 37
    double log_y[4];
    for (int i = 0; i < 4; i++)
        log_y[i] = (y[i] > 1e-300) ? std::log(y[i]) : -700.0;

    cx P0(0.0, 0.0);
    P0 += 1.0 * std::exp(0.0);

    cx P1(0.0, 0.0);
    P1 += 1.0 * std::exp(0.0);

    cx P2(0.0, 0.0);
    P2 += 1.0 * std::exp(0.0);

    cx P3(0.0, 0.0);
    P3 += 1.0 * std::exp(0.0);
    P3 += 1.0 * std::exp((4.0/7.0) * log_y[1]);

    cx P4(0.0, 0.0);
    P4 += 4.0 * std::exp(2.0 * log_y[3]);
    P4 += 8.0 * std::exp((4.0/7.0) * log_y[1] + 2.0 * log_y[3]);
    P4 += 4.0 * std::exp((8.0/7.0) * log_y[1] + 2.0 * log_y[3]);
    P4 += (4.0 * params[0]) * std::exp((1.0/3.0) * log_y[2]);
    P4 += (4.0 * params[1]) * std::exp((1.0/3.0) * log_y[2]);
    P4 += (4.0 * params[2]) * std::exp((1.0/3.0) * log_y[2]);
    P4 += (4.0 * params[0]) * std::exp((4.0/7.0) * log_y[1] + (1.0/3.0) * log_y[2]);
    P4 += (4.0 * params[1]) * std::exp((4.0/7.0) * log_y[1] + (1.0/3.0) * log_y[2]);
    P4 += (4.0 * params[2]) * std::exp((4.0/7.0) * log_y[1] + (1.0/3.0) * log_y[2]);
    P4 += 16.0 * std::exp(0.0);
    P4 += 16.0 * std::exp((4.0/7.0) * log_y[1]);
    P4 += 16.0 * std::exp((4.0/3.0) * log_y[0] + (4.0/7.0) * log_y[1]);
    P4 += 16.0 * std::exp((4.0/3.0) * log_y[0] + (8.0/7.0) * log_y[1]);

    cx P5(0.0, 0.0);
    P5 += 4.0 * std::exp(0.0);
    P5 += 4.0 * std::exp((4.0/7.0) * log_y[1]);

    cx result = (16.0/63.0);
    result *= std::exp((7.0/2.0) * std::log(P0));
    result *= std::exp((1.0/4.0) * std::log(P1));
    result *= std::exp((1.0/4.0) * std::log(P2));
    result *= std::exp((-3.0/2.0) * std::log(P3));
    result *= std::exp(-5.0 * std::log(P4));
    result *= std::exp(5.0 * std::log(P5));
    return result;
}

